{
  "manifest_version": 3,
  "name": "Claude Assistant",
  "version": "1.0.0",
  "description": "Summarize and explain page content with Claude.",
  "permissions": ["storage", "activeTab", "scripting"],
  "host_permissions": [
    "https://api.anthropic.com/*"
  ],
  "background": {
    "service_worker": "background.js"
  },
  "action": {
    "default_popup": "popup.html"
  },
  "content_scripts": [
    {
      "matches": ["<all_urls>"],
      "js": ["content.js"]
    }
  ]
}
